--]]

---@class LGameCommon
local LGameCommon = LxClass("LGameCommon", nil)

function LGameCommon.ShowCustomerBtnRegion()
	--- 东南亚、越南、俄罗斯、印泰
	if gLGameLanguage:IsSEALngRegion() or
			gLGameLanguage:IsVietnamRegion() or
			gLGameLanguage:IsRussiaRegion() or
			gLGameLanguage:IsIDRLngRegion()
	then
		local customerLink = LGameCommon.GetCustomerLink()
		if not string.isempty(customerLink) then
			return true
		else
			if LOG_INFO_ENABLED then
				printInfoNR2("客服按钮状态：","BIActivityConfigRef 的 customerLink 字段为空")
			end
		end
	end
	return false
end

function LGameCommon.GetCustomerLink()
	return GameTable.InnerActivityConfigRef["customerLink"]
end

---@return boolean 是否展示 联络客服 按钮
function LGameCommon.CheckShowCustomerBtn()
	if PRODUCT_G_VER and PRODUCT_G_VER > 0 then
		--- 提审环境屏蔽该功能
		if CS.IsWebGL() and LWxHelper.IsDouYinPlatform() then
			return true
		end
		return false
	end

	if gLGameLogin:IsOpenGm() then return true end

	if LGameCommon.ShowCustomerBtnRegion() then return true end

	return false
end